import{_ as e,o as a,c as r,a4 as d}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"电荷转移","description":"","frontmatter":{"title":"电荷转移","colorCause":"charge-transfer"},"headers":[],"relativePath":"zh/color-causes/charge-transfer.md","filePath":"zh/color-causes/charge-transfer.md","lastUpdated":1784177547000}'),o={name:"zh/color-causes/charge-transfer.md"};function n(s,t,i,h,l,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="电荷转移" tabindex="-1">电荷转移 <a class="header-anchor" href="#电荷转移" aria-label="Permalink to &quot;电荷转移&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>电荷转移是电子在相邻离子或同一离子的不同能级之间跳跃吸收光子 的过程。与 d-d 跃迁相比，电荷转移的吸收强度通常高 10²–10⁴ 倍， 因此即使致色离子浓度很低也能产生饱和浓艳的颜色。常见类型： <strong>金属-金属电荷转移（MMCT）</strong>、<strong>氧-金属电荷转移（OMCT）</strong>、 <strong>金属-配体电荷转移（MLCT）</strong>。</p><h2 id="致色机制" tabindex="-1">致色机制 <a class="header-anchor" href="#致色机制" aria-label="Permalink to &quot;致色机制&quot;">​</a></h2><p><strong>金属-金属电荷转移 (MMCT)</strong>：相邻两个金属离子之间电子转移。 经典案例：蓝宝石的 Fe²⁺–Ti⁴⁺，一个电子从 Fe 跃迁到 Ti，吸收 黄红光 → 透射蓝光。 <strong>氧-金属电荷转移 (OMCT)</strong>：O²⁻ → 金属离子（如 Fe³⁺、Mn⁴⁺） 电子转移。常见于蓝宝石（Fe²⁺–O–Ti⁴⁺）和黄绿色蓝宝石。 <strong>金属-配体电荷转移 (MLCT)</strong>：常见于有机宝石（如珍珠质）。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>转移对</th><th>化学式宿主</th><th>颜色</th></tr></thead><tbody><tr><td>Blue Sapphire / 蓝宝石</td><td>Fe²⁺–Ti⁴⁺</td><td>Al₂O₃</td><td>blue</td></tr><tr><td>Amethyst / 紫晶</td><td>Fe²⁺ → Fe⁴⁺ (via O²⁻)</td><td>SiO₂</td><td>violet</td></tr><tr><td>Yellow Sapphire / 黄宝石</td><td>Fe³⁺–O²⁻</td><td>Al₂O₃</td><td>yellow</td></tr><tr><td>Aquamarine (deep) / 海蓝宝</td><td>Fe²⁺–Fe³⁺</td><td>Be₃Al₂Si₆O₁₈</td><td>deep blue</td></tr><tr><td>Hematite / 赤铁矿</td><td>Fe²⁺–Fe³⁺</td><td>Fe₂O₃</td><td>red-brown</td></tr><tr><td>Kunzite / 孔赛石</td><td>Mn²⁺ → Mn⁴⁺</td><td>LiAlSi₂O₆</td><td>pink (fades with light)</td></tr></tbody></table><p><em>详见<a href="./intro.html">颜色成因总览</a>。</em></p>',8)])])}const _=e(o,[["render",n]]);export{u as __pageData,_ as default};
